
ALTER TABLE public.profiles
  ADD COLUMN IF NOT EXISTS is_placeholder BOOLEAN NOT NULL DEFAULT FALSE;

ALTER TABLE public.profiles ALTER COLUMN user_id DROP NOT NULL;

