WITH unit AS (SELECT id FROM public.units WHERE code = 'L01' LIMIT 1),
ger AS (SELECT id FROM public.profiles WHERE unit_id = (SELECT id FROM unit) AND posicao_organograma = 'gerente_unidade' LIMIT 1)
UPDATE public.profiles
SET lider_setor_id = (SELECT id FROM ger)
WHERE unit_id = (SELECT id FROM unit) AND posicao_organograma = 'encarregado';

WITH unit AS (SELECT id FROM public.units WHERE code = 'L01' LIMIT 1),
ger AS (SELECT id FROM public.profiles WHERE unit_id = (SELECT id FROM unit) AND posicao_organograma = 'gerente_unidade' LIMIT 1)
UPDATE public.profiles p_colab
SET lider_setor_id = COALESCE(
  (SELECT p_enc.id FROM public.profiles p_enc
   WHERE p_enc.unit_id = p_colab.unit_id
     AND p_enc.posicao_organograma = 'encarregado'
     AND p_enc.setor_organograma = p_colab.setor_organograma
   LIMIT 1),
  (SELECT id FROM ger)
)
WHERE p_colab.posicao_organograma = 'colaborador'
  AND p_colab.unit_id = (SELECT id FROM unit);
